export const PaymentScreen = ({
  config,
  productIds = [],
  walletRequest,
  accountId,
  onPurchaseSuccess,
  onWalletSuccess,
  onError,
}) => {
  const {
    status,
    capabilities,
    products,
    lastResult,
    error,
    initialize,
    fetchProducts,
    purchase,
    presentWallet,
    restorePurchases,
  } = usePayment(config);

  const [selectedProduct, setSelectedProduct] = useState(null);

  useEffect(() => {
    let mounted = true;

    (async () => {
      try {
        await initialize();
        if (productIds.length) {
          const fetched = await fetchProducts(productIds);
          if (mounted && fetched.length) {
            setSelectedProduct(fetched[0]);
          }
        }
      } catch (e) {
        onError?.(e);
      }
    })();

    return () => {
      mounted = false;
    };
  }, [initialize, fetchProducts, productIds, onError]);

  useEffect(() => {
    if (!lastResult) return;
    if (lastResult.type === 'wallet') {
      onWalletSuccess?.(lastResult);
    } else {
      onPurchaseSuccess?.(lastResult);
    }
  }, [lastResult, onPurchaseSuccess, onWalletSuccess]);

  useEffect(() => {
    if (error) {
      onError?.(error);
      Alert.alert('Payment Error', error.message);
    }
  }, [error, onError]);

  const canUseWallet = useMemo(() => {
    if (!capabilities) return false;
    return Platform.OS === 'ios' ? capabilities.supportsApplePay : capabilities.supportsGooglePay;
  }, [capabilities]);

  const handlePurchase = useCallback(async () => {
    if (!selectedProduct?.productId) {
      Alert.alert('Unavailable', 'No product selected.');
      return;
    }

    const result = await purchase({
      productId: selectedProduct.productId,
      quantity: 1,
      accountId,
      metadata: { source: 'payment_screen' },
    });

    if (result?.transactionId) {
      await PaymentModule.completeTransaction(result.transactionId);
    }
  }, [selectedProduct, purchase, accountId]);

  const handleWallet = useCallback(async () => {
    const result = await presentWallet({
      ...walletRequest,
      accountId,
      metadata: { source: 'payment_screen' },
    });

    if (result?.transactionId) {
      await PaymentModule.completeTransaction(result.transactionId);
    }
  }, [presentWallet, walletRequest, accountId]);

  const handleRestore = useCallback(async () => {
    const restored = await restorePurchases(accountId);
    Alert.alert('Restored', `Recovered ${restored.length} purchase(s).`);
  }, [restorePurchases, accountId]);

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Payments</Text>
      <Text style={styles.subtitle}>Platform: {Platform.OS}</Text>
      <Text style={styles.subtitle}>Status: {status}</Text>

      {status === PAYMENT_STATUS.INITIALIZING && <ActivityIndicator size="large" color="#111827" />}

      {products.length > 0 && (
        <View style={styles.section}>
          <Text style={styles.sectionTitle}>In-App Purchases</Text>
          {products.map((product) => {
            const active = selectedProduct?.productId === product.productId;
            return (
              <TouchableOpacity
                key={product.productId}
                style={[styles.productCard, active && styles.productCardActive]}
                onPress={() => setSelectedProduct(product)}
              >
                <Text style={styles.productTitle}>{product.title || product.productId}</Text>
                <Text style={styles.productPrice}>{product.localizedPrice || product.price}</Text>
              </TouchableOpacity>
            );
          })}
          <PaymentButton
            title="Buy Selected Product"
            onPress={handlePurchase}
            loading={status === PAYMENT_STATUS.PROCESSING}
            disabled={!selectedProduct}
          />
          <PaymentButton
            title="Restore Purchases"
            onPress={handleRestore}
            style={styles.secondaryButton}
            textStyle={styles.secondaryButtonText}
          />
        </View>
      )}

      {canUseWallet && walletRequest && (
        <View style={styles.section}>
          <Text style={styles.sectionTitle}>
            {Platform.OS === 'ios' ? 'Apple Pay' : 'Google Pay'}
          </Text>
          <PaymentButton
            title={Platform.OS === 'ios' ? 'Pay with Apple Pay' : 'Pay with Google Pay'}
            onPress={handleWallet}
            loading={status === PAYMENT_STATUS.PROCESSING}
          />
        </View>
      )}

      {!products.length && !canUseWallet && status === PAYMENT_STATUS.READY && (
        <Text style={styles.emptyText}>No payment methods available.</Text>
      )}
    </View>
  );
};

